import { jdFromDate, jdToDate, getSolarTermIndex } from './astronomical.js';
import { t, type Locale } from '../constants/i18n.js';
import type { SolarTerm } from './types.js';

/**
 * Lấy tên Tiết Khí theo index và locale.
 *
 * @param index - Index Tiết Khí (0-23, xem {@link getSolarTermIndex} trong astronomical.ts;
 *   0 = Xuân Phân, 18 = Đông Chí, 21 = Lập Xuân, ...)
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getSolarTermName(index: number, locale: Locale = 'vi'): string {
  const { solarTermNames } = t(locale);
  return solarTermNames[((index % 24) + 24) % 24] as string;
}

/**
 * Lấy Tiết Khí đang hiệu lực tại một ngày dương lịch cho trước.
 *
 * `getSolarTermIndex` (astronomical.ts) trả về kinh độ Mặt Trời tại thời điểm 00:00 (đầu
 * ngày) của `jdn`. Theo quy ước almanac truyền thống, một ngày được tính là "ngày
 * Tiết Khí X" nếu thời điểm chuyển Tiết Khí rơi vào bất kỳ lúc nào trong ngày đó —
 * tức là dùng giá trị tại 00:00 của ngày **kế tiếp** mới phản ánh đúng Tiết Khí đã
 * "chốt" cho ngày hiện tại. Vì vậy hàm này tra cứu tại `jd + 1`, không phải `jd`.
 *
 * @param day - Ngày dương lịch (1-31)
 * @param month - Tháng dương lịch (1-12)
 * @param year - Năm dương lịch
 * @param timeZone - Múi giờ (mặc định: 7 cho GMT+7 Việt Nam)
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 *
 * @example
 * ```typescript
 * getSolarTerm(21, 6, 2024);
 * // → { index: 6, name: 'Hạ Chí', date: { day: 21, month: 6, year: 2024 }, jd: ... }
 * ```
 */
export function getSolarTerm(
  day: number,
  month: number,
  year: number,
  timeZone: number = 7,
  locale: Locale = 'vi'
): SolarTerm {
  const jd = jdFromDate(day, month, year);
  const index = getSolarTermIndex(jd + 1, timeZone);
  return { index, name: getSolarTermName(index, locale), date: { day, month, year }, jd };
}

/** Một lần xuất hiện Tiết Khí, chưa gắn tên/locale — dữ liệu thô dùng để cache. */
export interface SolarTermOccurrence {
  index: number;
  jd: number;
}

/**
 * Cache kết quả quét theo `năm:timeZone` — phần quét (dưới đây) tốn ~370 lần tính
 * lượng giác mỗi năm, trong khi kết quả không đổi giữa các lần gọi cùng năm/timeZone
 * (chỉ locale khác nhau, mà locale không ảnh hưởng tới ngày/index tính được). Không
 * cần giới hạn kích thước cache: thực tế chỉ vài chục năm được truy vấn trong vòng
 * đời một ứng dụng lịch, chi phí bộ nhớ không đáng kể.
 */
const occurrencesCache = new Map<string, SolarTermOccurrence[]>();

/**
 * Quét kinh độ Mặt Trời để tìm toàn bộ Tiết Khí bắt đầu trong một năm dương lịch,
 * trả về dữ liệu thô (index + jd, chưa gắn tên/locale). Dùng nội bộ, chia sẻ giữa
 * {@link getSolarTermsInYear} (gắn tên theo locale) và `getTrucIndex` (truc-zodiac.ts,
 * chỉ cần jd/index để tìm mốc Tiết gần nhất, không cần tên).
 *
 * Quét trực tiếp trên kinh độ Mặt Trời (cùng công thức Hồ Ngọc Đức/Meeus dùng cho
 * Điểm Sóc và Trung Khí) thay vì suy ra ngày trung bình, nên chính xác đến từng ngày
 * kể cả ở các năm nhuận Dương lịch hoặc gần ranh giới năm.
 *
 * `getSolarTermIndex(jd)` phản ánh Tiết Khí tại 00:00 đầu ngày `jd`. Khi chỉ số này
 * đổi từ ngày `jd - 1` sang ngày `jd`, thời điểm chuyển Tiết Khí thực tế rơi vào
 * trong ngày `jd - 1` (xem giải thích chi tiết ở {@link getSolarTerm}) — nên ngày
 * được ghi nhận là `jd - 1`, không phải `jd`.
 */
export function getSolarTermOccurrencesInYear(year: number, timeZone: number): SolarTermOccurrence[] {
  const cacheKey = `${year}:${timeZone}`;
  const cached = occurrencesCache.get(cacheKey);
  if (cached) return cached;

  const startJd = jdFromDate(1, 1, year) - 5;
  const endJd = jdFromDate(31, 12, year) + 5;

  const occurrences: SolarTermOccurrence[] = [];
  let prevIndex = getSolarTermIndex(startJd, timeZone);
  for (let jd = startJd + 1; jd <= endJd; jd++) {
    const index = getSolarTermIndex(jd, timeZone);
    if (index !== prevIndex) {
      const termJd = jd - 1;
      const [, , jdYear] = jdToDate(termJd);
      if (jdYear === year) {
        occurrences.push({ index, jd: termJd });
      }
      prevIndex = index;
    }
  }

  occurrencesCache.set(cacheKey, occurrences);
  return occurrences;
}

/**
 * Liệt kê toàn bộ Tiết Khí bắt đầu trong một năm dương lịch (thường 24 hoặc 25 lần
 * xuất hiện tùy năm, do các Tiết Khí không rơi đúng vào ranh giới năm).
 *
 * @param year - Năm dương lịch
 * @param timeZone - Múi giờ (mặc định: 7 cho GMT+7 Việt Nam)
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 * @returns Mảng {@link SolarTerm} theo thứ tự thời gian tăng dần
 */
export function getSolarTermsInYear(
  year: number,
  timeZone: number = 7,
  locale: Locale = 'vi'
): SolarTerm[] {
  return getSolarTermOccurrencesInYear(year, timeZone).map(({ index, jd }) => {
    const [day, month, jdYear] = jdToDate(jd);
    return { index, name: getSolarTermName(index, locale), date: { day, month, year: jdYear }, jd };
  });
}
