import { HEAVENLY_STEMS } from '../constants/heavenly-stems.js';
import { EARTHLY_BRANCHES } from '../constants/earthly-branches.js';
import { FIVE_ELEMENTS } from '../constants/five-elements.js';
import { t, type Locale } from '../constants/i18n.js';
import { mod } from '../utils/math.js';
import { getNapAmElementIndex } from './ngu-hanh.js';

/** Kết quả trả về của {@link getYearDetails}. */
export interface YearDetails {
  can: string;
  chi: string;
  menh: string;
  /** Index Ngũ Hành của `menh` (0-4, vào FIVE_ELEMENTS) — dùng cho `getElementRelation` (ngu-hanh.ts). */
  menhIndex: number;
  fullString: string;
}

/**
 * Lấy ra chuỗi mô tả toàn bộ Can, Chi và Mệnh dựa vào số năm (Ví dụ: 2024)
 * Theo quy ước: Năm 4 (sau CN) là năm Giáp Tý (Can index 0, Chi index 0)
 *
 * Công thức Can Chi là chu kỳ 60 năm lặp lại vô hạn nên nhận mọi số năm nguyên,
 * kể cả năm 0 hoặc âm (trước Công Nguyên) — không giới hạn phạm vi như
 * `LichTa.toLunar` (phạm vi đó là do thuật toán tìm Điểm Sóc, không áp
 * dụng cho công thức Can Chi thuần).
 *
 * @param year - Năm (số nguyên bất kỳ, kể cả 0 hoặc âm)
 *
 * @example
 * ```typescript
 * getYearDetails(2024);
 * // → { can: 'Giáp', chi: 'Thìn', menh: 'Hỏa', menhIndex: 3, fullString: 'Giáp Thìn - Mệnh Hỏa' }
 * ```
 */
export function getYearDetails(year: number): YearDetails {
  // Tính index của Can và Chi dựa trên mốc năm gốc
  // Năm 1984, 2044 là Giáp Tý -> Offset để tính toán dễ nhất là lấy (year - 4) % hệ cơ số
  const stemIndex = mod(year - 4, 10);
  const branchIndex = mod(year - 4, 12);
  const elementIndex = getNapAmElementIndex(stemIndex, branchIndex);

  return {
    can: HEAVENLY_STEMS[stemIndex],
    chi: EARTHLY_BRANCHES[branchIndex],
    menh: FIVE_ELEMENTS[elementIndex],
    menhIndex: elementIndex,
    fullString: `${HEAVENLY_STEMS[stemIndex]} ${EARTHLY_BRANCHES[branchIndex]} - Mệnh ${FIVE_ELEMENTS[elementIndex]}`
  };
}

// ============================================================
// Giờ Hoàng Đạo
// ============================================================

/**
 * Bảng giờ Hoàng Đạo theo Chi của ngày.
 * Mỗi hàng tương ứng với 2 Chi (Tý-Ngọ, Sửu-Mùi, ...) → 6 nhóm.
 * Giá trị là index các Địa Chi tốt (6 giờ tốt trong 12 canh).
 */
const AUSPICIOUS_HOURS_TABLE: readonly (readonly number[])[] = [
  [0, 1, 3, 6, 7, 9],   // Ngày Tý (0) / Ngọ (6)
  [2, 3, 5, 8, 9, 11],  // Ngày Sửu (1) / Mùi (7)
  [0, 1, 4, 5, 7, 10],  // Ngày Dần (2) / Thân (8)
  [1, 2, 4, 7, 8, 10],  // Ngày Mão (3) / Dậu (9)
  [0, 3, 4, 6, 9, 10],  // Ngày Thìn (4) / Tuất (10)
  [2, 5, 6, 8, 11, 0],  // Ngày Tỵ (5) / Hợi (11)
] as const;

/**
 * Lấy danh sách 6 giờ Hoàng Đạo trong ngày.
 * Giờ Hoàng Đạo phụ thuộc vào Địa Chi của ngày.
 *
 * @param dayJd - Julian Day Number của ngày
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi', giữ nguyên hành vi cũ)
 * @returns Mảng 6 chuỗi tên Địa Chi (ví dụ: ["Tý", "Sửu", "Mão", "Ngọ", "Mùi", "Dậu"])
 */
export function getAuspiciousHours(dayJd: number, locale: Locale = 'vi'): string[] {
  const branchIndex = (dayJd + 1) % 12;
  // Nhóm theo 2 Chi (Tý-Ngọ, Sửu-Mùi, ...)
  const groupIndex = branchIndex % 6;
  const hourIndices = AUSPICIOUS_HOURS_TABLE[groupIndex];
  const { earthlyBranches } = t(locale);
  return hourIndices.map((i) => earthlyBranches[i] as string);
}

/**
 * Lấy index (0-11, theo thứ tự Địa Chi Tý→Hợi) của 6 giờ Hoàng Đạo trong ngày.
 *
 * Dùng khi cần một khoá ổn định, không phụ thuộc ngôn ngữ — ví dụ để map sang
 * icon riêng, hoặc tự tra bảng dịch của bạn thay vì dùng chuỗi tên có sẵn từ
 * {@link getAuspiciousHours}. Cả hai hàm dùng chung thứ tự dữ liệu nên
 * `getAuspiciousHourIndices(jd)[i]` luôn tương ứng với `getAuspiciousHours(jd)[i]`.
 *
 * @param dayJd - Julian Day Number của ngày
 * @returns Mảng 6 index Địa Chi (ví dụ: [0, 1, 3, 6, 7, 9])
 */
export function getAuspiciousHourIndices(dayJd: number): number[] {
  const branchIndex = (dayJd + 1) % 12;
  const groupIndex = branchIndex % 6;
  return [...AUSPICIOUS_HOURS_TABLE[groupIndex]];
}

/**
 * Lấy index (0-11, theo thứ tự Địa Chi Tý→Hợi) của 6 giờ Hắc Đạo (giờ xấu) trong
 * ngày — phần bù của {@link getAuspiciousHourIndices} trong 12 canh giờ (6 giờ
 * Hoàng Đạo + 6 giờ Hắc Đạo = đủ 12 canh).
 *
 * @param dayJd - Julian Day Number của ngày
 * @returns Mảng 6 index Địa Chi, tăng dần
 */
export function getInauspiciousHourIndices(dayJd: number): number[] {
  const auspicious = new Set(getAuspiciousHourIndices(dayJd));
  const inauspicious: number[] = [];
  for (let i = 0; i < 12; i++) {
    if (!auspicious.has(i)) inauspicious.push(i);
  }
  return inauspicious;
}

/**
 * Lấy danh sách 6 giờ Hắc Đạo (giờ xấu) trong ngày theo locale (xem
 * {@link getInauspiciousHourIndices}).
 *
 * @param dayJd - Julian Day Number của ngày
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 * @returns Mảng 6 chuỗi tên Địa Chi
 */
export function getInauspiciousHours(dayJd: number, locale: Locale = 'vi'): string[] {
  const { earthlyBranches } = t(locale);
  return getInauspiciousHourIndices(dayJd).map((i) => earthlyBranches[i] as string);
}
