/**
 * Lấy bộ dịch theo locale
 * @param locale - Ngôn ngữ ('vi' | 'en' | 'ja' | 'ko')
 */
export function t(locale: Locale) {
  return translations[locale];
}

/**
 * Lấy tên con giáp theo locale
 * @param branchIndex - Index Địa Chi (0-11)
 * @param locale - Ngôn ngữ
 */
export function getZodiacAnimal(branchIndex: number, locale: Locale = 'vi'): string {
  return translations[locale].zodiacAnimals[branchIndex % 12];
}

/**
 * Lấy nhãn thứ trong tuần theo locale, xoay vòng theo ngày bắt đầu tuần.
 * @param locale - Ngôn ngữ
 * @param firstDayOfWeek - Ngày bắt đầu tuần: 0 = Chủ Nhật (mặc định), 1 = Thứ Hai
 */
export function getWeekDayLabels(locale: Locale, firstDayOfWeek: FirstDayOfWeek = 0): string[] {
  const { weekDays } = translations[locale];
  return firstDayOfWeek === 0 ? [...weekDays] : [...weekDays.slice(1), weekDays[0]];
}
