import { LichTa } from '../core/calendar-engine.js';
import type { LunarDate } from '../core/types.js';

/** Một ô ngày trong lưới lịch tháng. */
export interface CalendarDayCell {
  solar: Date;
  lunar: LunarDate;
  isToday: boolean;
  isSelected: boolean;
  isCurrentMonth: boolean;
  /** Số tuần trong năm (ISO-8601) của hàng chứa ô này — giống nhau cho cả 7 ô trong hàng. */
  weekNumber: number;
}

/** Ngày bắt đầu tuần: 0 = Chủ Nhật (mặc định, giống `Date.getDay()`), 1 = Thứ Hai. */
export type FirstDayOfWeek = 0 | 1;

function dateKey(date: Date): string {
  return `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`;
}

/**
 * Tính số tuần theo chuẩn ISO-8601: tuần bắt đầu Thứ Hai, tuần 1 của năm là
 * tuần chứa Thứ Năm đầu tiên (tương đương: tuần chứa ngày 4/1).
 */
export function getISOWeekNumber(date: Date): number {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = (d.getUTCDay() + 6) % 7; // 0 = Thứ Hai .. 6 = Chủ Nhật
  d.setUTCDate(d.getUTCDate() - dayNum + 3); // Nhích về Thứ Năm cùng tuần ISO

  const firstThursday = new Date(Date.UTC(d.getUTCFullYear(), 0, 4));
  const firstThursdayDayNum = (firstThursday.getUTCDay() + 6) % 7;
  firstThursday.setUTCDate(firstThursday.getUTCDate() - firstThursdayDayNum + 3);

  return 1 + Math.round((d.getTime() - firstThursday.getTime()) / 604800000);
}

/**
 * Dựng lưới 42 ô (6 tuần x 7 ngày) cho 1 tháng dương lịch, gồm ngày tràn từ
 * tháng trước/sau để lấp đầy tuần đầu/cuối, mỗi ô kèm ngày âm tương ứng.
 *
 * Logic này trước đây bị lặp lại độc lập ở Calendar.tsx/vue/svelte — tách ra
 * đây để có 1 nguồn tính toán duy nhất (tránh 3 bản có thể lệch nhau khi sửa
 * riêng lẻ), dùng chung cho cả Calendar và DatePicker ở mọi framework.
 *
 * @param month - Tháng dương lịch (1-12)
 * @param year - Năm dương lịch
 * @param selectedDate - Ngày đang được chọn (nếu có), dùng để đánh dấu `isSelected`
 * @param firstDayOfWeek - Ngày bắt đầu tuần: 0 = Chủ Nhật (mặc định), 1 = Thứ Hai
 */
export function getCalendarGrid(
  month: number,
  year: number,
  selectedDate?: Date | null,
  firstDayOfWeek: FirstDayOfWeek = 0
): CalendarDayCell[] {
  const grid: CalendarDayCell[] = [];
  const firstDay = new Date(year, month - 1, 1);
  const lastDay = new Date(year, month, 0);
  const startingDayOfWeek = (firstDay.getDay() - firstDayOfWeek + 7) % 7;
  const daysInMonth = lastDay.getDate();
  const todayKey = dateKey(new Date());
  const selectedKey = selectedDate ? dateKey(selectedDate) : '';
  const prevMonthLastDay = new Date(year, month - 1, 0).getDate();

  const pushCell = (solar: Date, d: number, m: number, y: number, isCurrentMonth: boolean) => {
    grid.push({
      solar,
      lunar: LichTa.toLunar(d, m, y),
      isToday: dateKey(solar) === todayKey,
      isSelected: dateKey(solar) === selectedKey,
      isCurrentMonth,
      weekNumber: 0, // gán lại theo từng hàng ở bước cuối, xem vòng lặp bên dưới
    });
  };

  for (let i = startingDayOfWeek - 1; i >= 0; i--) {
    const d = prevMonthLastDay - i;
    const m = month - 1 < 1 ? 12 : month - 1;
    const y = month - 1 < 1 ? year - 1 : year;
    pushCell(new Date(y, m - 1, d), d, m, y, false);
  }

  for (let d = 1; d <= daysInMonth; d++) {
    pushCell(new Date(year, month - 1, d), d, month, year, true);
  }

  const remaining = 42 - grid.length;
  for (let d = 1; d <= remaining; d++) {
    const m = month + 1 > 12 ? 1 : month + 1;
    const y = month + 1 > 12 ? year + 1 : year;
    pushCell(new Date(y, m - 1, d), d, m, y, false);
  }

  // Số tuần của cả hàng lấy theo Thứ Năm trong hàng đó — đây là ngày ISO-8601
  // dùng để định danh tuần, nên đúng chuẩn dù hàng bắt đầu Chủ Nhật hay Thứ Hai.
  const thursdayOffset = (4 - firstDayOfWeek + 7) % 7;
  for (let row = 0; row < grid.length; row += 7) {
    const weekNumber = getISOWeekNumber(grid[row + thursdayOffset].solar);
    for (let i = row; i < row + 7; i++) {
      grid[i].weekNumber = weekNumber;
    }
  }

  return grid;
}
