import { t, type Locale } from '../constants/i18n.js';
import { mod } from '../utils/math.js';
import { jdToDate } from './astronomical.js';
import { getSolarTermOccurrencesInYear } from './tiet-khi.js';

// ============================================================
// Trực (12 Kiến Trừ)
// ============================================================

const TRUC_COUNT = 12;

/**
 * Tính index Trực (0-11: Kiến, Trừ, Mãn, Bình, Định, Chấp, Phá, Nguy, Thành, Thu, Khai, Bế)
 * tại một ngày dương lịch (Julian Day Number).
 *
 * Trực được neo theo 12 Tiết (Lập Xuân, Kinh Trập, Thanh Minh, ...) — tức các index
 * lẻ trong 24 Tiết Khí ({@link import('./tiet-khi.js').getSolarTermsInYear}, `tiet-khi.ts`) —
 * KHÔNG theo số tháng âm lịch, vì tháng nhuận âm lịch không tương ứng với một Tiết mới
 * (dùng số tháng âm lịch sẽ cho kết quả sai trong các tháng nhuận).
 *
 * Ngày Tiết bắt đầu luôn là "Kiến" (index 0), Trực tăng dần 1 mỗi ngày sau đó và
 * quay lại "Kiến" vào Tiết kế tiếp. Vì mỗi Tiết dài ~15 ngày (không chia hết cho
 * chu kỳ 12 ngày của Trực), một số Trực sẽ bị lặp lại hoặc rút ngắn giữa 2 Tiết
 * liên tiếp — đây là đặc tính vốn có của hệ Kiến Trừ truyền thống, không phải lỗi.
 *
 * Dùng `getSolarTermOccurrencesInYear` (dữ liệu thô, có cache theo năm+timeZone)
 * thay vì `getSolarTermsInYear` công khai — tránh tính tên/locale không cần dùng
 * tới, và tránh quét lại kinh độ Mặt Trời mỗi lần gọi khi hàm này được gọi lặp lại
 * cho nhiều ngày cùng năm (vd. dựng lịch Trực cho cả tháng/năm).
 *
 * @param jd - Julian Day Number của ngày cần tra
 * @param timeZone - Múi giờ (mặc định: 7 cho GMT+7 Việt Nam)
 */
export function getTrucIndex(jd: number, timeZone: number = 7): number {
  const [, , year] = jdToDate(jd);
  // Quét cả năm trước/sau để không bỏ sót Tiết gần ranh giới năm dương lịch
  // (vd. đầu tháng 1 vẫn thuộc Tiết Đại Tuyết bắt đầu từ đầu tháng 12 năm trước).
  const tietTerms = [year - 1, year, year + 1]
    .flatMap((y) => getSolarTermOccurrencesInYear(y, timeZone))
    .filter((term) => term.index % 2 === 1); // 12 Tiết = index lẻ, bỏ 12 Khí (index chẵn)

  let governingTietJd = -Infinity;
  for (const term of tietTerms) {
    if (term.jd <= jd && term.jd > governingTietJd) {
      governingTietJd = term.jd;
    }
  }

  return mod(jd - governingTietJd, TRUC_COUNT);
}

/**
 * Lấy tên Trực theo index và locale.
 *
 * @param index - Index Trực (0-11, xem {@link getTrucIndex})
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getTrucName(index: number, locale: Locale = 'vi'): string {
  const { trucNames } = t(locale);
  return trucNames[mod(index, TRUC_COUNT)] as string;
}

/**
 * Lấy tên Trực tại một ngày dương lịch (Julian Day Number).
 *
 * @param jd - Julian Day Number của ngày cần tra
 * @param timeZone - Múi giờ (mặc định: 7 cho GMT+7 Việt Nam)
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getTruc(jd: number, timeZone: number = 7, locale: Locale = 'vi'): string {
  return getTrucName(getTrucIndex(jd, timeZone), locale);
}

/**
 * Mức tốt/xấu tổng quát của mỗi Trực (0 = Xấu, 1 = Trung bình, 2 = Tốt).
 *
 * Chỉ phân loại dứt khoát 4/12 Trực có sự đồng thuận rất cao giữa các nguồn:
 * Phá và Nguy luôn được xem là 2 Trực xấu nhất; Thành và Khai luôn được xem là 2
 * Trực tốt nhất. 8 Trực còn lại (Kiến, Trừ, Mãn, Bình, Định, Chấp, Thu, Bế) được
 * xếp "Trung bình" — KHÔNG phải vì chúng thực sự trung tính, mà vì mức tốt/xấu
 * chi tiết của chúng phụ thuộc vào từng việc cụ thể (nên/kỵ làm gì) và có dị bản
 * giữa các nguồn, nên repo này không tự khẳng định dứt khoát khi chưa đối chiếu
 * được một nguồn cụ thể. Nếu cần phân loại chi tiết hơn, nên tự bổ sung dựa trên
 * nguồn tham khảo bạn tin cậy thay vì dùng bảng này làm chỗ dựa duy nhất.
 */
const TRUC_QUALITY_INDEX: readonly number[] = [1, 1, 1, 1, 1, 1, 0, 0, 2, 1, 2, 1];

/**
 * Lấy index mức tốt/xấu (0-2) của một Trực — xem giải thích độ tin cậy ở
 * {@link TRUC_QUALITY_INDEX}.
 *
 * @param trucIndex - Index Trực (0-11, xem {@link getTrucIndex})
 */
export function getTrucQualityIndex(trucIndex: number): number {
  return TRUC_QUALITY_INDEX[mod(trucIndex, TRUC_COUNT)] as number;
}

/**
 * Lấy tên mức tốt/xấu của một Trực theo locale (xem {@link getTrucQualityIndex}).
 *
 * @param trucIndex - Index Trực (0-11, xem {@link getTrucIndex})
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getTrucQuality(trucIndex: number, locale: Locale = 'vi'): string {
  const { trucQualityNames } = t(locale);
  return trucQualityNames[getTrucQualityIndex(trucIndex)] as string;
}

// ============================================================
// Tuổi Xung Khắc (Lục Xung — Lục Hại — Tứ Hành Xung)
// ============================================================

/**
 * Lấy Chi đối xung (Lục Xung) với một Chi cho trước — 2 Chi cách nhau đúng 6 vị
 * trí trong vòng tròn 12 Chi: Tý-Ngọ, Sửu-Mùi, Dần-Thân, Mão-Dậu, Thìn-Tuất, Tỵ-Hợi.
 *
 * @param branchIndex - Index Địa Chi (0-11, vào EARTHLY_BRANCHES)
 * @returns Index Địa Chi đối xung
 */
export function getXungBranchIndex(branchIndex: number): number {
  return mod(branchIndex + 6, 12);
}

/**
 * Kiểm tra 2 Chi (tuổi) có phạm Lục Xung với nhau không.
 *
 * @param branchIndexA - Index Địa Chi thứ nhất (0-11)
 * @param branchIndexB - Index Địa Chi thứ hai (0-11)
 */
export function isXung(branchIndexA: number, branchIndexB: number): boolean {
  return getXungBranchIndex(mod(branchIndexA, 12)) === mod(branchIndexB, 12);
}

/**
 * Bảng Lục Hại: Tý-Mùi, Sửu-Ngọ, Dần-Tỵ, Mão-Thìn, Thân-Hợi, Dậu-Tuất.
 * Giá trị tại index i là Chi bị hại với Chi i (quan hệ đối xứng).
 */
const HAI_BRANCH_TARGET: readonly number[] = [7, 6, 5, 4, 3, 2, 1, 0, 11, 10, 9, 8];

/**
 * Lấy Chi bị Lục Hại với một Chi cho trước (xem {@link HAI_BRANCH_TARGET}).
 *
 * @param branchIndex - Index Địa Chi (0-11, vào EARTHLY_BRANCHES)
 * @returns Index Địa Chi bị hại
 */
export function getHaiBranchIndex(branchIndex: number): number {
  return HAI_BRANCH_TARGET[mod(branchIndex, 12)] as number;
}

/**
 * Kiểm tra 2 Chi (tuổi) có phạm Lục Hại với nhau không.
 *
 * @param branchIndexA - Index Địa Chi thứ nhất (0-11)
 * @param branchIndexB - Index Địa Chi thứ hai (0-11)
 */
export function isHai(branchIndexA: number, branchIndexB: number): boolean {
  return getHaiBranchIndex(mod(branchIndexA, 12)) === mod(branchIndexB, 12);
}

/**
 * Bảng Tứ Hành Xung: 3 nhóm, mỗi nhóm 4 Chi được xem là xung khắc lẫn nhau —
 *   Nhóm 0: Tý, Mão, Ngọ, Dậu (Tứ Chính)
 *   Nhóm 1: Dần, Tỵ, Thân, Hợi (Tứ Sinh)
 *   Nhóm 2: Sửu, Thìn, Mùi, Tuất (Tứ Mộ)
 * Giá trị tại index i là nhóm (0-2) chứa Chi i.
 */
const TU_HANH_XUNG_GROUP: readonly number[] = [0, 2, 1, 0, 2, 1, 0, 2, 1, 0, 2, 1];

/** 3 nhóm Tứ Hành Xung, mỗi nhóm là mảng 4 index Địa Chi (xem {@link TU_HANH_XUNG_GROUP}). */
const TU_HANH_XUNG_MEMBERS: readonly (readonly number[])[] = [
  [0, 3, 6, 9],   // Tý, Mão, Ngọ, Dậu
  [2, 5, 8, 11],  // Dần, Tỵ, Thân, Hợi
  [1, 4, 7, 10],  // Sửu, Thìn, Mùi, Tuất
];

/**
 * Lấy nhóm Tứ Hành Xung (0-2) chứa một Chi cho trước.
 *
 * @param branchIndex - Index Địa Chi (0-11, vào EARTHLY_BRANCHES)
 * @returns Index nhóm (0-2, xem {@link getTuHanhXungGroupMembers})
 */
export function getTuHanhXungGroupIndex(branchIndex: number): number {
  return TU_HANH_XUNG_GROUP[mod(branchIndex, 12)] as number;
}

/**
 * Lấy 4 Chi thuộc cùng nhóm Tứ Hành Xung với một Chi cho trước (bao gồm cả chính nó).
 *
 * @param branchIndex - Index Địa Chi (0-11, vào EARTHLY_BRANCHES)
 * @returns Mảng 4 index Địa Chi cùng nhóm
 */
export function getTuHanhXungGroupMembers(branchIndex: number): number[] {
  return [...TU_HANH_XUNG_MEMBERS[getTuHanhXungGroupIndex(branchIndex)]];
}

/**
 * Kiểm tra 2 Chi (tuổi) khác nhau có cùng nhóm Tứ Hành Xung không.
 *
 * @param branchIndexA - Index Địa Chi thứ nhất (0-11)
 * @param branchIndexB - Index Địa Chi thứ hai (0-11)
 */
export function isTuHanhXung(branchIndexA: number, branchIndexB: number): boolean {
  const a = mod(branchIndexA, 12);
  const b = mod(branchIndexB, 12);
  return a !== b && getTuHanhXungGroupIndex(a) === getTuHanhXungGroupIndex(b);
}

/** Kết quả trả về của {@link getZodiacConflicts}. */
export interface ZodiacConflicts {
  xung: boolean;
  hai: boolean;
  tuHanhXung: boolean;
}

/**
 * Kiểm tra toàn bộ quan hệ "kỵ tuổi" (Lục Xung, Lục Hại, Tứ Hành Xung) giữa 2 tuổi
 * (Chi năm sinh). Không loại trừ lẫn nhau — 1 cặp Chi có thể vừa Lục Xung vừa cùng
 * nhóm Tứ Hành Xung (vd. Tý-Ngọ là cả 2).
 *
 * @param branchIndexA - Index Địa Chi (con giáp) thứ nhất (0-11)
 * @param branchIndexB - Index Địa Chi (con giáp) thứ hai (0-11)
 *
 * @example
 * ```typescript
 * getZodiacConflicts(0, 6); // Tý (0) và Ngọ (6)
 * // → { xung: true, hai: false, tuHanhXung: true }
 * ```
 */
export function getZodiacConflicts(branchIndexA: number, branchIndexB: number): ZodiacConflicts {
  return {
    xung: isXung(branchIndexA, branchIndexB),
    hai: isHai(branchIndexA, branchIndexB),
    tuHanhXung: isTuHanhXung(branchIndexA, branchIndexB),
  };
}
