const PI = Math.PI;

function INT(d: number): number {
  return Math.floor(d);
}

// ============================================================
// Julian Day Number
// ============================================================

/**
 * Chuyển ngày Gregorian sang Julian Day Number.
 *
 * @param dd - Ngày (1-31)
 * @param mm - Tháng (1-12)
 * @param yy - Năm
 */
export function jdFromDate(dd: number, mm: number, yy: number): number {
  const a = INT((14 - mm) / 12);
  const y = yy + 4800 - a;
  const m = mm + 12 * a - 3;
  let jd = dd + INT((153 * m + 2) / 5) + 365 * y + INT(y / 4) - INT(y / 100) + INT(y / 400) - 32045;
  if (jd < 2299161) {
    jd = dd + INT((153 * m + 2) / 5) + 365 * y + INT(y / 4) - 32083;
  }
  return jd;
}

/**
 * Chuyển Julian Day Number sang ngày Gregorian.
 *
 * @param jd - Julian Day Number
 * @returns Tuple [day, month, year]
 */
export function jdToDate(jd: number): [number, number, number] {
  let a: number, b: number, c: number;
  if (jd > 2299160) {
    a = jd + 32044;
    b = INT((4 * a + 3) / 146097);
    c = a - INT((b * 146097) / 4);
  } else {
    b = 0;
    c = jd + 32082;
  }
  const d = INT((4 * c + 3) / 1461);
  const e = c - INT((1461 * d) / 4);
  const m = INT((5 * e + 2) / 153);
  const day = e - INT((153 * m + 2) / 5) + 1;
  const month = m + 3 - 12 * INT(m / 10);
  const year = b * 100 + d - 4800 + INT(m / 10);
  return [day, month, year];
}

// ============================================================
// Điểm Sóc (New Moon) — Thuật toán Hồ Ngọc Đức / Jean Meeus
// ============================================================

/**
 * Tính thời điểm điểm Sóc (New Moon) thứ k
 * (đo bằng số ngày Julian kể từ 1/1/4713 BC trưa UTC).
 *
 * k=0 tương ứng New Moon ngày 1/1/1900 13:52 UTC.
 *
 * @param k - Số thứ tự New Moon
 */
function NewMoon(k: number): number {
  const T = k / 1236.85;
  const T2 = T * T;
  const T3 = T2 * T;
  const dr = PI / 180;

  let Jd1 = 2415020.75933 + 29.53058868 * k + 0.0001178 * T2 - 0.000000155 * T3;
  Jd1 = Jd1 + 0.00033 * Math.sin((166.56 + 132.87 * T - 0.009173 * T2) * dr);

  // Mean anomaly của Mặt Trời
  const M = 359.2242 + 29.10535608 * k - 0.0000333 * T2 - 0.00000347 * T3;
  // Mean anomaly của Mặt Trăng
  const Mpr = 306.0253 + 385.81691806 * k + 0.0107306 * T2 + 0.00001236 * T3;
  // Argument of latitude của Mặt Trăng
  const F = 21.2964 + 390.67050646 * k - 0.0016528 * T2 - 0.00000239 * T3;

  // Hiệu chỉnh
  let C1 = (0.1734 - 0.000393 * T) * Math.sin(M * dr) + 0.0021 * Math.sin(2 * dr * M);
  C1 = C1 - 0.4068 * Math.sin(Mpr * dr) + 0.0161 * Math.sin(dr * 2 * Mpr);
  C1 = C1 - 0.0004 * Math.sin(dr * 3 * Mpr);
  C1 = C1 + 0.0104 * Math.sin(dr * 2 * F) - 0.0051 * Math.sin(dr * (M + Mpr));
  C1 = C1 - 0.0074 * Math.sin(dr * (M - Mpr)) + 0.0004 * Math.sin(dr * (2 * F + M));
  C1 = C1 - 0.0004 * Math.sin(dr * (2 * F - M)) - 0.0006 * Math.sin(dr * (2 * F + Mpr));
  C1 = C1 + 0.001 * Math.sin(dr * (2 * F - Mpr)) + 0.0005 * Math.sin(dr * (2 * Mpr + M));

  const JdNew = Jd1 + C1;
  return JdNew;
}

/**
 * Tính ngày Julian (integer) của điểm Sóc thứ k theo múi giờ.
 *
 * @param k - Số thứ tự New Moon
 * @param timeZone - Múi giờ (7 = GMT+7)
 */
export function getNewMoonDay(k: number, timeZone: number): number {
  return INT(NewMoon(k) + 0.5 + timeZone / 24);
}

// ============================================================
// Kinh độ Mặt Trời (Sun Longitude)
// ============================================================

/**
 * Tính kinh độ Mặt Trời biểu kiến (0°-360°) tại ngày Julian cho trước.
 * Dùng làm cơ sở chung cho cả Trung Khí ({@link getSunLongitude}, bước 30°)
 * và Tiết Khí ({@link getSolarTermIndex}, bước 15°).
 *
 * @param jdn - Julian Day Number
 * @param timeZone - Múi giờ
 */
function sunLongitudeDegrees(jdn: number, timeZone: number): number {
  const T = (jdn - 2451545.5 - timeZone / 24) / 36525;
  const T2 = T * T;
  const dr = PI / 180;

  // Mean longitude
  const M = 357.5291 + 35999.0503 * T - 0.0001559 * T2 - 0.00000048 * T * T2;

  // Mean longitude
  const L0 = 280.46645 + 36000.76983 * T + 0.0003032 * T2;

  let DL = (1.9146 - 0.004817 * T - 0.000014 * T2) * Math.sin(dr * M);
  DL = DL + (0.019993 - 0.000101 * T) * Math.sin(dr * 2 * M) + 0.00029 * Math.sin(dr * 3 * M);

  let L = L0 + DL;
  // Chuẩn hóa
  L = L - 360 * INT(L / 360);
  return L;
}

/**
 * Tính kinh độ Mặt Trời tại ngày Julian cho trước.
 * Trả về index 0-11 (mỗi 30°), dùng để xác định Trung khí.
 *
 * Index 9 = Đông Chí (270°-300°)
 *
 * @param jdn - Julian Day Number
 * @param timeZone - Múi giờ
 */
export function getSunLongitude(jdn: number, timeZone: number): number {
  return INT(sunLongitudeDegrees(jdn, timeZone) / 30);
}

/**
 * Tính index Tiết Khí (0-23, mỗi tiết cách nhau 15°) tại ngày Julian cho trước.
 *
 * Index 0 = Xuân Phân (kinh độ 0°), Index 18 = Đông Chí (270°),
 * tăng dần theo chiều quỹ đạo — xem thứ tự đầy đủ trong
 * `SOLAR_TERM_NAMES` (`tiet-khi.ts`).
 *
 * @param jdn - Julian Day Number
 * @param timeZone - Múi giờ
 */
export function getSolarTermIndex(jdn: number, timeZone: number): number {
  return INT(sunLongitudeDegrees(jdn, timeZone) / 15);
}
