import { t, type Locale } from '../constants/i18n.js';
import { mod } from '../utils/math.js';

// ============================================================
// Ngũ Hành Nạp Âm (Mệnh) — dùng chung cho Năm, Tháng, Ngày, Giờ
// ============================================================

/**
 * Bảng Nạp Âm Ngũ Hành của 60 Hoa Giáp, gộp theo 30 nhóm (2 tổ hợp Can Chi liền kề
 * trong chu kỳ 60 dùng chung 1 hành — ví dụ Giáp Tý & Ất Sửu đều là Kim/Hải Trung
 * Kim). Bảng Nạp Âm KHÔNG có công thức đóng (closed-form): đây là bảng tra cứu
 * chuẩn theo quy ước truyền thống, không suy ra được từ Can/Chi bằng phép cộng đơn
 * giản. (Bản trước của repo dùng công thức cộng trọng số Can+Chi, sai lệch 48/60
 * tổ hợp — tức 80% — so với bảng chuẩn khi đối chiếu; đã thay bằng bảng tra cứu này.)
 *
 * Giá trị là index vào `FIVE_ELEMENTS` ['Kim', 'Mộc', 'Thủy', 'Hỏa', 'Thổ'].
 * Nhóm 0 = Giáp Tý/Ất Sửu (Hải Trung Kim), nhóm 1 = Bính Dần/Đinh Mão (Lư Trung
 * Hỏa), ..., nhóm 29 = Nhâm Tuất/Quý Hợi (Đại Hải Thủy).
 */
const NAP_AM_ELEMENT_INDEX: readonly number[] = [
  0, 3, 1, 4, 0, 3, 2, 4, 0, 1, 2, 4, 3, 1, 2,
  0, 3, 1, 4, 0, 3, 2, 4, 0, 1, 2, 4, 3, 1, 2,
];

/**
 * Tính vị trí (0-59) của một tổ hợp Can Chi trong chu kỳ 60 Hoa Giáp, từ index
 * Thiên Can (0-9) và Địa Chi (0-11). Dò tuyến tính 60 giá trị — hàm này không nằm
 * trên đường găng hiệu năng (chỉ gọi khi cần tra Nạp Âm), nên ưu tiên đơn giản/khó
 * sai hơn là tự suy công thức CRT đóng.
 */
function getSexagenaryIndex(stemIndex: number, branchIndex: number): number {
  for (let i = 0; i < 60; i++) {
    if (i % 10 === stemIndex && i % 12 === branchIndex) {
      return i;
    }
  }
  // Không xảy ra với Can Chi hợp lệ — Can/Chi hợp lệ luôn cùng tính chẵn/lẻ
  // (Can Dương luôn đi với Chi Dương, Can Âm luôn đi với Chi Âm).
  throw new RangeError(`Lichta: Invalid Can Chi combination (stem=${stemIndex}, chi=${branchIndex})`);
}

/**
 * Tính index Ngũ Hành Nạp Âm (0-4, vào FIVE_ELEMENTS) từ index Can + Chi.
 * Export nội bộ — dùng bởi `almanac.ts` ({@link getYearDetails}), không thuộc public API.
 */
export function getNapAmElementIndex(stemIndex: number, branchIndex: number): number {
  const sexagenaryIndex = getSexagenaryIndex(stemIndex, branchIndex);
  return NAP_AM_ELEMENT_INDEX[Math.floor(sexagenaryIndex / 2)] as number;
}

/**
 * Lấy tên Ngũ Hành theo index và locale.
 *
 * @param index - Index Ngũ Hành (0-4, vào FIVE_ELEMENTS: Kim, Mộc, Thủy, Hỏa, Thổ)
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getElementName(index: number, locale: Locale = 'vi'): string {
  return t(locale).fiveElements[mod(index, 5)] as string;
}

/**
 * Tính index Ngũ Hành Nạp Âm (0-4, vào FIVE_ELEMENTS) của ngày, dùng chung bảng
 * Nạp Âm 60 Hoa Giáp với `getYearDetails` (almanac.ts). Chỉ số Can/Chi tính giống hệt
 * {@link import('./can-chi.js').getDayCanChi}.
 *
 * @param jd - Julian Day Number
 */
export function getDayElementIndex(jd: number): number {
  const stemIndex = (jd + 9) % 10;
  const branchIndex = (jd + 1) % 12;
  return getNapAmElementIndex(stemIndex, branchIndex);
}

/**
 * Tính Mệnh (Ngũ Hành Nạp Âm) của ngày theo locale (xem {@link getDayElementIndex}).
 *
 * @param jd - Julian Day Number
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getDayElement(jd: number, locale: Locale = 'vi'): string {
  return getElementName(getDayElementIndex(jd), locale);
}

/**
 * Tính index Ngũ Hành Nạp Âm (0-4, vào FIVE_ELEMENTS) của tháng âm lịch. Chỉ số
 * Can/Chi tính giống hệt {@link import('./can-chi.js').getMonthCanChi}.
 *
 * @param lunarMonth - Tháng âm lịch (1-12)
 * @param lunarYear - Năm âm lịch
 */
export function getMonthElementIndex(lunarMonth: number, lunarYear: number): number {
  const yearStemIndex = (lunarYear + 6) % 10;
  const monthStemOffset = (yearStemIndex % 5) * 2 + 2;
  const monthStemIndex = (monthStemOffset + lunarMonth - 1) % 10;
  const monthBranchIndex = (lunarMonth + 1) % 12;
  return getNapAmElementIndex(monthStemIndex, monthBranchIndex);
}

/**
 * Tính Mệnh (Ngũ Hành Nạp Âm) của tháng âm lịch theo locale (xem {@link getMonthElementIndex}).
 *
 * @param lunarMonth - Tháng âm lịch (1-12)
 * @param lunarYear - Năm âm lịch
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getMonthElement(lunarMonth: number, lunarYear: number, locale: Locale = 'vi'): string {
  return getElementName(getMonthElementIndex(lunarMonth, lunarYear), locale);
}

/**
 * Tính index Ngũ Hành Nạp Âm (0-4, vào FIVE_ELEMENTS) của giờ. Chỉ số Can/Chi tính
 * giống hệt {@link import('./can-chi.js').getHourCanChi}.
 *
 * @param hour - Giờ (0-23)
 * @param dayJd - Julian Day Number của ngày
 */
export function getHourElementIndex(hour: number, dayJd: number): number {
  const hourBranchIndex = Math.floor((hour + 1) / 2) % 12;
  const dayStemIndex = (dayJd + 9) % 10;
  const hourStemOffset = (dayStemIndex % 5) * 2;
  const hourStemIndex = (hourStemOffset + hourBranchIndex) % 10;
  return getNapAmElementIndex(hourStemIndex, hourBranchIndex);
}

/**
 * Tính Mệnh (Ngũ Hành Nạp Âm) của giờ theo locale (xem {@link getHourElementIndex}).
 *
 * @param hour - Giờ (0-23)
 * @param dayJd - Julian Day Number của ngày
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 */
export function getHourElement(hour: number, dayJd: number, locale: Locale = 'vi'): string {
  return getElementName(getHourElementIndex(hour, dayJd), locale);
}

// ============================================================
// Tương Sinh — Tương Khắc
// ============================================================

/** Ngũ Hành mà mỗi hành (theo index FIVE_ELEMENTS) SINH ra: Kim→Thủy, Mộc→Hỏa, Thủy→Mộc, Hỏa→Thổ, Thổ→Kim. */
const ELEMENT_SINH_TARGET: readonly number[] = [2, 3, 1, 4, 0];

/** Ngũ Hành mà mỗi hành (theo index FIVE_ELEMENTS) KHẮC: Kim→Mộc, Mộc→Thổ, Thủy→Hỏa, Hỏa→Kim, Thổ→Thủy. */
const ELEMENT_KHAC_TARGET: readonly number[] = [1, 4, 3, 0, 2];

/**
 * Tính quan hệ Ngũ Hành từ `fromIndex` tới `toIndex`, trả về index 0-4:
 *   0 = sinh (from sinh to)      2 = khắc (from khắc to)      4 = hòa (cùng hành)
 *   1 = được sinh (to sinh from) 3 = bị khắc (to khắc from)
 *
 * Với 5 hành, 2 hành khác nhau bất kỳ luôn rơi vào đúng 1 trong 4 quan hệ trên
 * (mỗi hành có đúng 1 hành sinh nó, 1 hành nó sinh, 1 hành khắc nó, 1 hành nó khắc)
 * — không có trường hợp mơ hồ.
 *
 * @param fromIndex - Index Ngũ Hành thứ nhất (0-4, vào FIVE_ELEMENTS)
 * @param toIndex - Index Ngũ Hành thứ hai (0-4, vào FIVE_ELEMENTS)
 */
export function getElementRelationIndex(fromIndex: number, toIndex: number): number {
  const a = mod(fromIndex, 5);
  const b = mod(toIndex, 5);
  if (a === b) return 4;
  if (ELEMENT_SINH_TARGET[a] === b) return 0;
  if (ELEMENT_SINH_TARGET[b] === a) return 1;
  if (ELEMENT_KHAC_TARGET[a] === b) return 2;
  return 3; // Trường hợp còn lại duy nhất: ELEMENT_KHAC_TARGET[b] === a
}

/**
 * Lấy tên quan hệ Ngũ Hành giữa 2 hành theo locale (xem {@link getElementRelationIndex}).
 *
 * @param fromIndex - Index Ngũ Hành thứ nhất (0-4, vào FIVE_ELEMENTS)
 * @param toIndex - Index Ngũ Hành thứ hai (0-4, vào FIVE_ELEMENTS)
 * @param locale - Ngôn ngữ hiển thị (mặc định: 'vi')
 *
 * @example
 * ```typescript
 * // Mộc (1) và Hỏa (3): Mộc sinh Hỏa
 * getElementRelation(1, 3); // → 'Tương sinh'
 * getElementRelation(3, 1); // → 'Được sinh' (từ góc nhìn của Hỏa: được Mộc sinh)
 * ```
 */
export function getElementRelation(fromIndex: number, toIndex: number, locale: Locale = 'vi'): string {
  const { elementRelationNames } = t(locale);
  return elementRelationNames[getElementRelationIndex(fromIndex, toIndex)] as string;
}
