/**
 * Modulo luôn trả về số không âm (khác toán tử `%` gốc của JS, vốn trả về số âm
 * khi vế trái âm — ví dụ `-1 % 10 === -1`, trong khi `mod(-1, 10) === 9`).
 *
 * Dùng chung cho các module can-chi/ngũ-hành/trực (không phải public API).
 */
export function mod(n: number, m: number): number {
  return ((n % m) + m) % m;
}
